Shader shader = new Shader(0);
float[] values = {1.0, 2.0, 3.0};
shader.uniformf("uniform_name", values);

// Create a new shader object and load the shader from the specified file
Shader myShader = Shader.load("myShader");

// Define a matrix object to hold the 4x4 transformation matrix
Matrix4f myTransform = new Matrix4f();

// Set the transformation matrix values using the appropriate methods
myTransform.setIdentity();
myTransform.setRotate(90, 1.0f, 0.0f, 0.0f);

// Set the uniform variable in the shader to the transformation matrix
myShader.uniformMat4("transform", myTransform);
